CREATE OR REPLACE FUNCTION sync_module_rule_expression_to_rule_expression()
RETURNS TRIGGER AS $$
BEGIN
    IF pg_trigger_depth() > 1 THEN
        RETURN COALESCE(NEW, OLD);
    END IF;

    IF (TG_OP = 'INSERT') THEN
        INSERT INTO rule_expression (
            rule_expression_id, value, context, status_id, owner_id,
            date_created, date_updated, update_id, "version"
        )
        VALUES (
            NEW.rule_expression_id, NEW.value, NEW.context, NEW.status_id, NEW.owner_id,
            NEW.date_created, NEW.date_updated, NEW.update_id, NEW."version"
        )
        ON CONFLICT (rule_expression_id) DO UPDATE SET
            value = EXCLUDED.value,
            context = EXCLUDED.context,
            status_id = EXCLUDED.status_id,
            owner_id = EXCLUDED.owner_id,
            date_created = EXCLUDED.date_created,
            date_updated = EXCLUDED.date_updated,
            update_id = EXCLUDED.update_id,
            "version" = EXCLUDED."version";
        RETURN NEW;
    ELSIF (TG_OP = 'UPDATE') THEN
        UPDATE rule_expression SET
            value = NEW.value,
            context = NEW.context,
            status_id = NEW.status_id,
            owner_id = NEW.owner_id,
            date_created = NEW.date_created,
            date_updated = NEW.date_updated,
            update_id = NEW.update_id,
            "version" = NEW."version"
        WHERE rule_expression_id = OLD.rule_expression_id;
        RETURN NEW;
    ELSIF (TG_OP = 'DELETE') THEN
        DELETE FROM rule_expression WHERE rule_expression_id = OLD.rule_expression_id;
        RETURN OLD;
    END IF;
END;
$$ LANGUAGE plpgsql;

