DROP TRIGGER IF EXISTS trg_sync_module_rule_expression ON module_rule_expression;
CREATE TRIGGER trg_sync_module_rule_expression
AFTER INSERT OR UPDATE OR DELETE ON module_rule_expression
FOR EACH ROW EXECUTE FUNCTION sync_module_rule_expression_to_rule_expression();

DROP TRIGGER IF EXISTS trg_sync_rule_expression_to_module ON rule_expression;
CREATE TRIGGER trg_sync_rule_expression_to_module
AFTER INSERT OR UPDATE OR DELETE ON rule_expression
FOR EACH ROW EXECUTE FUNCTION sync_rule_expression_to_module_rule_expression();

CREATE OR REPLACE FUNCTION sync_module_rule_to_rule() RETURNS TRIGGER AS $$ BEGIN IF pg_trigger_depth() > 1 THEN RETURN COALESCE(NEW, OLD); END IF;
IF (TG_OP = 'INSERT') THEN INSERT INTO rule ( rule_id, oc_oid, name, description, enabled, rule_expression_id, status_id, owner_id, date_created, date_updated, update_id, "version" ) VALUES ( NEW.rule_id, NEW.oc_oid, NEW.name, NEW.description, NEW.enabled, NEW.rule_expression_id, NEW.status_id, NEW.owner_id, NEW.date_created, NEW.date_updated, NEW.update_id, NEW."version" ) ON CONFLICT (rule_id) DO UPDATE SET oc_oid = EXCLUDED.oc_oid, name = EXCLUDED.name, description = EXCLUDED.description, enabled = EXCLUDED.enabled, rule_expression_id = EXCLUDED.rule_expression_id, status_id = EXCLUDED.status_id, owner_id = EXCLUDED.owner_id, date_created = EXCLUDED.date_created, date_updated = EXCLUDED.date_updated, update_id = EXCLUDED.update_id, "version" = EXCLUDED."version"; RETURN NEW; ELSIF (TG_OP = 'UPDATE') THEN UPDATE rule SET oc_oid = NEW.oc_oid, name = NEW.name, description = NEW.description, enabled = NEW.enabled, rule_expression_id = NEW.rule_expression_id, status_id = NEW.status_id, owner_id = NEW.owner_id, date_created = NEW.date_created, date_updated = NEW.date_updated, update_id = NEW.update_id, "version" = NEW."version" WHERE rule_id = OLD.rule_id; RETURN NEW; ELSIF (TG_OP = 'DELETE') THEN DELETE FROM rule WHERE rule_id = OLD.rule_id; RETURN OLD; END IF; END; $$ LANGUAGE plpgsql;
CREATE OR REPLACE FUNCTION sync_rule_to_module_rule() RETURNS TRIGGER AS $$ BEGIN IF pg_trigger_depth() > 1 THEN RETURN COALESCE(NEW, OLD); END IF;
IF (TG_OP = 'INSERT') THEN INSERT INTO module_rule ( rule_id, oc_oid, name, description, enabled, rule_expression_id, status_id, owner_id, date_created, date_updated, update_id, "version" ) VALUES ( NEW.rule_id, NEW.oc_oid, NEW.name, NEW.description, NEW.enabled, NEW.rule_expression_id, NEW.status_id, NEW.owner_id, NEW.date_created, NEW.date_updated, NEW.update_id, NEW."version" ) ON CONFLICT (rule_id) DO UPDATE SET oc_oid = EXCLUDED.oc_oid, name = EXCLUDED.name, description = EXCLUDED.description, enabled = EXCLUDED.enabled, rule_expression_id = EXCLUDED.rule_expression_id, status_id = EXCLUDED.status_id, owner_id = EXCLUDED.owner_id, date_created = EXCLUDED.date_created, date_updated = EXCLUDED.date_updated, update_id = EXCLUDED.update_id, "version" = EXCLUDED."version"; RETURN NEW; ELSIF (TG_OP = 'UPDATE') THEN UPDATE module_rule SET oc_oid = NEW.oc_oid, name = NEW.name, description = NEW.description, enabled = NEW.enabled, rule_expression_id = NEW.rule_expression_id, status_id = NEW.status_id, owner_id = NEW.owner_id, date_created = NEW.date_created, date_updated = NEW.date_updated, update_id = NEW.update_id, "version" = NEW."version" WHERE rule_id = OLD.rule_id; RETURN NEW; ELSIF (TG_OP = 'DELETE') THEN DELETE FROM module_rule WHERE rule_id = OLD.rule_id; RETURN OLD; END IF; END; $$ LANGUAGE plpgsql;
DROP TRIGGER IF EXISTS trg_sync_module_rule ON module_rule; CREATE TRIGGER trg_sync_module_rule AFTER INSERT OR UPDATE OR DELETE ON module_rule FOR EACH ROW EXECUTE FUNCTION sync_module_rule_to_rule();
DROP TRIGGER IF EXISTS trg_sync_rule_to_module ON rule; CREATE TRIGGER trg_sync_rule_to_module AFTER INSERT OR UPDATE OR DELETE ON rule FOR EACH ROW EXECUTE FUNCTION sync_rule_to_module_rule();

